def get_category(client):
    """从client字段提取品类"""
    if not client:
        return None
    if '-' in client:
        return client.split('-')[0]
    return client

def get_industry(client):
    """获取行业"""
    cat = get_category(client)
    return INDUSTRY_MAP.get(cat, cat or "综合")

def get_target_audience(client):
    """获取目标受众"""
    cat = get_category(client)
    return TARGET_AUDIENCE_MAP.get(cat, ["大众消费者"])

